// MPEG1 Layer 3, 128kbps, 44100Hz, Joint Stereo
// Frame header bytes:
//   0xFF 0xFB: sync(11) + MPEG1(2) + Layer3(2) + no_CRC(1) = 1111 1111 1111 1011
//   0x90: bitrate=1001(128kbps) + freq=00(44100) + pad=0 + private=0
//   0x64: stereo=00 + mode_ext=01 + copyright=1 + original=0 + emphasis=00
// Actually let's use standard safe values:
//   0xFF 0xFB = sync + MPEG1 + Layer3 + NoCRC 
//   0x90 = 128kbps + 44100Hz + no padding
//   0x00 = Joint Stereo + mode_ext=00

// For MPEG1 L3 stereo, side info is 32 bytes
// A valid silent frame: header(4) + sideinfo(32) + maindata(381) = 417 bytes
// Side info with zero granule data means silence

function createSilentMP3Frame() {
  const frame = Buffer.alloc(417, 0);
  // Frame sync
  frame[0] = 0xFF;
  frame[1] = 0xFB; // MPEG1, Layer3, NoCRC
